"use client";

/**
 * Mic Selector
 * @registryCategory audio
 */

import { useEffect, useRef, useState } from "react";

import { useAudioDevices as useSharedAudioDevices } from "@/hooks/use-audio-devices";
import { cn } from "@/lib/utils";
import { LiveWaveform } from "./live-waveform";

// ---- ICONS -----------------------------------------------------------------

function MicIcon({ className }: { className?: string }) {
  return (
    <svg
      className={className}
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth="2"
      strokeLinecap="round"
      strokeLinejoin="round"
    >
      <rect x="9" y="2" width="6" height="11" rx="3" />
      <path d="M5 10a7 7 0 0 0 14 0" />
      <line x1="12" y1="19" x2="12" y2="22" />
    </svg>
  );
}

function MicOffIcon({ className }: { className?: string }) {
  return (
    <svg
      className={className}
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth="2"
      strokeLinecap="round"
      strokeLinejoin="round"
    >
      <line x1="2" y1="2" x2="22" y2="22" />
      <path d="M18.89 13.23A7.12 7.12 0 0 0 19 12" />
      <path d="M5 10a7 7 0 0 0 12 5" />
      <path d="M15 9.34V4a3 3 0 0 0-5.68-1.33" />
      <path d="M9 9v3a3 3 0 0 0 5.12 2.12" />
      <line x1="12" y1="19" x2="12" y2="22" />
    </svg>
  );
}

function ChevronUpDownIcon({ className }: { className?: string }) {
  return (
    <svg
      className={className}
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth="2"
      strokeLinecap="round"
      strokeLinejoin="round"
    >
      <path d="m7 15 5 5 5-5" />
      <path d="m7 9 5-5 5 5" />
    </svg>
  );
}

function CheckIcon({ className }: { className?: string }) {
  return (
    <svg
      className={className}
      viewBox="0 0 24 24"
      fill="none"
      stroke="currentColor"
      strokeWidth="2"
      strokeLinecap="round"
      strokeLinejoin="round"
    >
      <path d="M20 6 9 17l-5-5" />
    </svg>
  );
}

// ---- TYPES -----------------------------------------------------------------

export interface AudioDevice {
  deviceId: string;
  label: string;
  groupId: string;
}

export interface MicSelectorProps {
  value?: string;
  onValueChange?: (deviceId: string) => void;
  muted?: boolean;
  onMutedChange?: (muted: boolean) => void;
  disabled?: boolean;
  className?: string;
}

// ---- COMPONENT -------------------------------------------------------------

export function MicSelector({
  value,
  onValueChange,
  muted,
  onMutedChange,
  disabled,
  className,
}: MicSelectorProps) {
  const { devices, loading, error, hasPermission, loadDevices } =
    useAudioDevices();
  const [selectedDevice, setSelectedDevice] = useState<string>(value || "");
  const [internalMuted, setInternalMuted] = useState(false);
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);

  const isMuted = muted !== undefined ? muted : internalMuted;

  useEffect(() => {
    if (value !== undefined) {
      setSelectedDevice(value);
    }
  }, [value]);

  const defaultDeviceId = devices[0]?.deviceId || "";

  useEffect(() => {
    if (!selectedDevice && defaultDeviceId) {
      setSelectedDevice(defaultDeviceId);
      onValueChange?.(defaultDeviceId);
    }
  }, [defaultDeviceId, onValueChange, selectedDevice]);

  const currentDevice = devices.find(
    (device) => device.deviceId === selectedDevice
  ) ||
    devices[0] || {
      label: loading ? "Loading..." : "No microphone",
      deviceId: "",
      groupId: "",
    };

  const handleDeviceSelect = (deviceId: string, event?: React.MouseEvent) => {
    event?.preventDefault();
    setSelectedDevice(deviceId);
    onValueChange?.(deviceId);
  };

  const handleDropdownOpenChange = async (open: boolean) => {
    setIsDropdownOpen(open);
    if (open && !hasPermission && !loading) {
      await loadDevices();
    }
  };

  const toggleMute = () => {
    const nextMuted = !isMuted;
    if (muted === undefined) {
      setInternalMuted(nextMuted);
    }
    onMutedChange?.(nextMuted);
  };

  const isPreviewActive = isDropdownOpen && !isMuted;

  useEffect(() => {
    if (!isDropdownOpen) {
      return;
    }

    const handleClick = (event: MouseEvent) => {
      if (
        containerRef.current &&
        !containerRef.current.contains(event.target as Node)
      ) {
        setIsDropdownOpen(false);
      }
    };

    document.addEventListener("mousedown", handleClick);
    return () => document.removeEventListener("mousedown", handleClick);
  }, [isDropdownOpen]);

  useEffect(() => {
    if (!isDropdownOpen) {
      return;
    }

    const handleKey = (event: KeyboardEvent) => {
      if (event.key === "Escape") {
        setIsDropdownOpen(false);
      }
    };

    document.addEventListener("keydown", handleKey);
    return () => document.removeEventListener("keydown", handleKey);
  }, [isDropdownOpen]);

  return (
    <div
      ref={containerRef}
      className="relative inline-block"
      data-slot="mic-selector"
    >
      <button
        type="button"
        onClick={() => void handleDropdownOpenChange(!isDropdownOpen)}
        disabled={loading || disabled}
        className={cn(
          "hover:bg-accent flex w-40 min-w-0 shrink cursor-pointer items-center gap-1.5 rounded-md px-3 py-1.5 text-sm transition-colors sm:w-48",
          "disabled:pointer-events-none disabled:opacity-50",
          className
        )}
      >
        {isMuted ? (
          <MicOffIcon className="h-4 w-4 flex-shrink-0" />
        ) : (
          <MicIcon className="h-4 w-4 flex-shrink-0" />
        )}
        <span className="min-w-0 flex-1 truncate text-left text-xs sm:text-sm">
          {currentDevice.label}
        </span>
        <ChevronUpDownIcon className="h-3 w-3 flex-shrink-0" />
      </button>

      {isDropdownOpen && (
        <div className="absolute bottom-full left-1/2 z-50 mb-1 w-72 -translate-x-1/2 rounded-md border bg-popover p-1 text-popover-foreground shadow-md">
          {loading ? (
            <div className="px-2 py-1.5 text-sm text-muted-foreground">
              Loading devices...
            </div>
          ) : error ? (
            <div className="px-2 py-1.5 text-sm text-muted-foreground">
              Error: {error}
            </div>
          ) : (
            devices.map((device) => (
              <button
                key={device.deviceId}
                type="button"
                onClick={(event) => handleDeviceSelect(device.deviceId, event)}
                className="flex w-full items-center justify-between rounded-sm px-2 py-1.5 text-sm hover:bg-accent hover:text-accent-foreground"
              >
                <span className="truncate">{device.label}</span>
                {selectedDevice === device.deviceId && (
                  <CheckIcon className="h-4 w-4 flex-shrink-0" />
                )}
              </button>
            ))
          )}
          {devices.length > 0 && (
            <>
              <div className="my-1 h-px bg-border" />
              <div className="flex items-center gap-2 p-2">
                <button
                  type="button"
                  onClick={(event) => {
                    event.preventDefault();
                    toggleMute();
                  }}
                  className="inline-flex h-8 items-center gap-2 rounded-md px-3 text-sm hover:bg-accent"
                >
                  {isMuted ? (
                    <MicOffIcon className="h-4 w-4" />
                  ) : (
                    <MicIcon className="h-4 w-4" />
                  )}
                  <span className="text-sm">{isMuted ? "Unmute" : "Mute"}</span>
                </button>
                <div className="bg-accent ml-auto w-16 overflow-hidden rounded-md p-1.5">
                  <LiveWaveform
                    active={isPreviewActive}
                    deviceId={selectedDevice || defaultDeviceId}
                    mode="static"
                    height={15}
                    barWidth={3}
                    barGap={1}
                  />
                </div>
              </div>
            </>
          )}
        </div>
      )}
    </div>
  );
}

MicSelector.displayName = "MicSelector";

// ---- HOOK: useAudioDevices -------------------------------------------------

export function useAudioDevices() {
  const {
    devices,
    error,
    hasEnumerated,
    hasPermission,
    isRequesting,
    requestPermission,
  } = useSharedAudioDevices({ kind: "audioinput" });

  return {
    devices: devices.map((device) => ({
      deviceId: device.deviceId,
      label: device.label,
      groupId: device.groupId,
    })),
    loading: !hasEnumerated || isRequesting,
    error,
    hasPermission,
    loadDevices: requestPermission,
  };
}

"use client";

/**
 * useAudioDevices
 * @registryDescription Hook for enumerating audio input devices with permission handling.
 * @registryVariant audio
 */

import { useCallback, useEffect, useState } from "react";

// ---- TYPES -----------------------------------------------------------------

interface AudioDevice {
  /** Unique device identifier */
  deviceId: string;
  /** Human-readable device label (empty until permission granted) */
  label: string;
  /** Device kind: audioinput, audiooutput, videoinput */
  kind: MediaDeviceKind;
  /** Group ID (devices from same hardware share a groupId) */
  groupId: string;
}

interface UseAudioDevicesOptions {
  /** Filter to specific device kind. Default: "audioinput" */
  kind?: MediaDeviceKind;
  /** Whether to request permission on mount. Default: false */
  requestOnMount?: boolean;
}

interface UseAudioDevicesReturn {
  /** Available audio devices */
  devices: AudioDevice[];
  /** Currently active device ID */
  activeDeviceId: string | null;
  /** Active MediaStream from selected device */
  stream: MediaStream | null;
  /** Whether permission has been granted */
  hasPermission: boolean;
  /** Whether we're requesting permission */
  isRequesting: boolean;
  /** Whether the initial device enumeration has completed */
  hasEnumerated: boolean;
  /** Error message */
  error: string | null;
  /** Request microphone permission and enumerate devices */
  requestPermission: () => Promise<void>;
  /** Select a specific device by ID */
  selectDevice: (deviceId: string) => Promise<void>;
  /** Stop the active stream */
  stopStream: () => void;
}

// ---- HELPERS ---------------------------------------------------------------

function formatDeviceLabel(device: MediaDeviceInfo, kind: MediaDeviceKind) {
  const fallbackPrefix = kind === "audioinput" ? "Microphone" : "Speaker";
  const fallback = `${fallbackPrefix} ${device.deviceId.slice(0, 8)}`;
  return (device.label || fallback).replace(/\s*\([^)]*\)/g, "").trim();
}

function stopTracks(stream: MediaStream | null) {
  if (!stream) {
    return;
  }

  stream.getTracks().forEach((track) => track.stop());
}

// ---- HOOK ------------------------------------------------------------------

export function useAudioDevices(
  options: UseAudioDevicesOptions = {}
): UseAudioDevicesReturn {
  const { kind = "audioinput", requestOnMount = false } = options;

  const [devices, setDevices] = useState<AudioDevice[]>([]);
  const [activeDeviceId, setActiveDeviceId] = useState<string | null>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [hasPermission, setHasPermission] = useState(false);
  const [isRequesting, setIsRequesting] = useState(false);
  const [hasEnumerated, setHasEnumerated] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const enumerateDevices = useCallback(async () => {
    if (
      typeof navigator === "undefined" ||
      !navigator.mediaDevices?.enumerateDevices
    ) {
      setError("MediaDevices API not available");
      setHasEnumerated(true);
      return;
    }

    try {
      const allDevices = await navigator.mediaDevices.enumerateDevices();
      const filtered = allDevices
        .filter((device) => device.kind === kind)
        .map((device) => ({
          deviceId: device.deviceId,
          label: formatDeviceLabel(device, kind),
          kind: device.kind,
          groupId: device.groupId,
        }));

      setDevices(filtered);
      setActiveDeviceId((currentDeviceId) => {
        if (
          currentDeviceId &&
          filtered.some((device) => device.deviceId === currentDeviceId)
        ) {
          return currentDeviceId;
        }

        return filtered[0]?.deviceId ?? null;
      });
      setHasEnumerated(true);
    } catch {
      setError("Failed to enumerate devices");
      setHasEnumerated(true);
    }
  }, [kind]);

  const requestPermission = useCallback(async () => {
    if (
      typeof navigator === "undefined" ||
      !navigator.mediaDevices?.getUserMedia
    ) {
      setError("getUserMedia not available");
      return;
    }

    setIsRequesting(true);
    setError(null);

    try {
      stopTracks(stream);

      const constraints: MediaStreamConstraints = {
        audio: kind === "audioinput" ? true : true,
      };
      const mediaStream =
        await navigator.mediaDevices.getUserMedia(constraints);

      setStream(mediaStream);
      setHasPermission(true);

      const tracks = mediaStream.getAudioTracks();
      if (tracks.length > 0) {
        const settings = tracks[0].getSettings();
        setActiveDeviceId(settings.deviceId || null);
      }

      await enumerateDevices();
    } catch (err) {
      if (err instanceof DOMException) {
        switch (err.name) {
          case "NotAllowedError":
            setError("Microphone permission denied");
            break;
          case "NotFoundError":
            setError("No microphone found");
            break;
          case "NotReadableError":
            setError("Microphone is in use by another application");
            break;
          default:
            setError(`Microphone error: ${err.message}`);
        }
      } else {
        setError("Failed to access microphone");
      }
    } finally {
      setIsRequesting(false);
      setHasEnumerated(true);
    }
  }, [enumerateDevices, kind, stream]);

  const selectDevice = useCallback(
    async (deviceId: string) => {
      if (
        typeof navigator === "undefined" ||
        !navigator.mediaDevices?.getUserMedia
      ) {
        return;
      }

      stopTracks(stream);
      setError(null);
      setIsRequesting(true);

      try {
        const mediaStream = await navigator.mediaDevices.getUserMedia({
          audio: { deviceId: { exact: deviceId } },
        });
        setStream(mediaStream);
        setActiveDeviceId(deviceId);
        setHasPermission(true);
        await enumerateDevices();
      } catch {
        setError("Failed to switch device");
      } finally {
        setIsRequesting(false);
        setHasEnumerated(true);
      }
    },
    [enumerateDevices, stream]
  );

  const stopStream = useCallback(() => {
    stopTracks(stream);
    setStream(null);
    setActiveDeviceId(null);
  }, [stream]);

  useEffect(() => {
    if (requestOnMount) {
      void requestPermission();
      return;
    }

    void enumerateDevices();
  }, [enumerateDevices, requestOnMount, requestPermission]);

  useEffect(() => {
    if (typeof navigator === "undefined" || !navigator.mediaDevices) {
      return;
    }

    const handler = () => {
      void enumerateDevices();
    };

    navigator.mediaDevices.addEventListener("devicechange", handler);
    return () => {
      navigator.mediaDevices.removeEventListener("devicechange", handler);
    };
  }, [enumerateDevices]);

  useEffect(() => {
    return () => {
      stopTracks(stream);
    };
  }, [stream]);

  return {
    devices,
    activeDeviceId,
    stream,
    hasPermission,
    isRequesting,
    hasEnumerated,
    error,
    requestPermission,
    selectDevice,
    stopStream,
  };
}

export type { AudioDevice, UseAudioDevicesOptions, UseAudioDevicesReturn };
